def generate_compiled_insight(calc_snapshot: dict, sections: list[dict]) -> str:
    """
    Собирает живой инсайт-пересказ из уже рассчитанных данных.
    Ничего не вычисляет — только сжимает и переформулирует.
    """

    def _first_sentence(text: str, max_len: int = 130) -> str:
        text = text.strip()
        dot = text.find(". ")
        sentence = text[: dot + 1] if 0 < dot < max_len else text[:max_len]
        return sentence.rstrip(" .")

    def _extract_block(text: str, marker: str) -> str:
        idx = text.find(marker)
        if idx == -1:
            return ""
        start = idx + len(marker)
        end = text.find("\n\n", start)
        chunk = text[start:end].strip() if end != -1 else text[start:].strip()
        return chunk

    def _manifestation(s: dict) -> str:
        raw = _extract_block(s.get("text", ""), "🔹 Как проявляется:\n")
        return _first_sentence(raw) if raw else ""

    def _risks(s: dict) -> str:
        raw = _extract_block(s.get("text", ""), "⚠️ Риски:\n")
        return _first_sentence(raw, 90) if raw else ""

    def _focus(s: dict) -> str:
        raw = _extract_block(s.get("text", ""), "🎯 Фокус периода:\n")
        return _first_sentence(raw) if raw else ""

    def _lc(s: str) -> str:
        return s[:1].lower() + s[1:] if s else ""

    by_title = {s["title"]: s for s in sections}
    phys    = by_title.get("Физическое тело")   or (sections[0] if sections else None)
    mental  = by_title.get("Ментальное тело")    or (sections[2] if len(sections) > 2 else None)
    life    = by_title.get("Жизненная задача")   or (sections[3] if len(sections) > 3 else None)
    higher  = by_title.get("Высшее Я")           or (sections[5] if len(sections) > 5 else None)
    cycle_s = next((s for s in sections if "цикл" in s["title"].lower()), None)

    cs = calc_snapshot or {}
    blocks: list[str] = []

    blocks.append("Я посмотрел твою карту — там очень интересная картина.")

    if phys:
        m = _manifestation(phys)
        line = (
            f"По физическому уровню у тебя вибрация {phys.get('vibration', '')} "
            f"({phys.get('planet', '')})"
        )
        if m:
            line += f" — {_lc(m)}"
        blocks.append(line + ".")

    if mental:
        m = _manifestation(mental)
        r = _risks(mental)
        line = f"По ментальному полю — {_lc(m) if m else '...'}"
        if r:
            line += f". Из-за этого нередко появляется {_lc(r)}"
        blocks.append(line + ".")

    if life:
        m = _manifestation(life)
        r = _risks(life)
        line = f"Жизненная задача у тебя — {_lc(m) if m else '...'}"
        if r:
            line += f". И одновременно с этим — риск: {_lc(r)}"
        blocks.append(line + ".")

    if higher:
        m = _manifestation(higher)
        blocks.append(
            f"По более глубоким уровням — Высшее Я у тебя "
            + (f"{_lc(m)}" if m else "несёт особый архетип")
            + f" ({higher.get('planet', '')})."
        )

    if cycle_s and cs:
        f_text = _focus(cycle_s) or _manifestation(cycle_s)
        line = (
            f"Сейчас ты в {cs.get('cycle_number', '?')}-м жизненном цикле "
            f"(возраст {cs.get('cycle_start_age', '?')}–{cs.get('cycle_end_age', '?')} лет), "
            f"планета — {cycle_s.get('planet', '')}"
        )
        if f_text:
            line += f". Фокус: {_lc(f_text)}"
        blocks.append(line + ".")

    blocks.append("\nИ это только верхний слой. Там дальше намного глубже.")

    blocks.append(
        "\nЯ сейчас вижу полную картину по тебе:\n"
        "— сильные стороны\n"
        "— где деньги\n"
        "— где блоки\n"
        "— как у тебя идут жизненные циклы\n\n"
        "Но это уже разворачивается в полном разборе."
    )

    return "\n".join(blocks)


def build_pdf_report(
    fio: str,
    birth_date: str,
    sections: list[dict],
    calc_snapshot: dict | None = None,
) -> str | None:
    if not REPORTLAB_AVAILABLE:
        print("ReportLab недоступен (REPORTLAB_AVAILABLE=False), PDF не создаётся")
        return None

    def _is_valid_font_file(path: str) -> bool:
        if not os.path.exists(path):
            return False
        try:
            with open(path, "rb") as f:
                head = f.read(4)
            # TrueType: 00010000, OpenType: OTTO, TTC: ttcf
            return head in (b"\x00\x01\x00\x00", b"OTTO", b"ttcf")
        except Exception as e:
            print("ERROR:", e)
            return False

    playfair_regular_path = os.path.join(BASE_DIR, "fonts", "PlayfairDisplay-Regular.ttf")
    playfair_bold_path = os.path.join(BASE_DIR, "fonts", "PlayfairDisplay-Bold.ttf")
    fallback_font_path = os.path.join(BASE_DIR, "fonts", "ArialUnicode.ttf")

    font_name = "Helvetica"
    try:
        if _is_valid_font_file(playfair_regular_path) and _is_valid_font_file(playfair_bold_path):
            registered = set(pdfmetrics.getRegisteredFontNames())
            if "SoulFont" not in registered:
                pdfmetrics.registerFont(TTFont("SoulFont", playfair_regular_path))
            if "SoulFont-Bold" not in registered:
                pdfmetrics.registerFont(TTFont("SoulFont-Bold", playfair_bold_path))
            pdfmetrics.registerFontFamily("SoulFont", normal="SoulFont", bold="SoulFont-Bold")
            font_name = "SoulFont"
        elif _is_valid_font_file(fallback_font_path):
            if "SoulFont" not in set(pdfmetrics.getRegisteredFontNames()):
                pdfmetrics.registerFont(TTFont("SoulFont", fallback_font_path))
            font_name = "SoulFont"
    except Exception as e:
        print("ERROR:", e)
        # Не валим генерацию PDF из-за проблем с файлом шрифта.
        font_name = "Helvetica"

    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY, TA_LEFT

    fd, pdf_path = tempfile.mkstemp(prefix="soul_report_", suffix=".pdf")
    os.close(fd)

    C_TEXT = colors.HexColor("#000000")
    C_HEAD = colors.HexColor("#222222")
    C_MUTED = colors.HexColor("#555555")
    C_BORDER = colors.HexColor("#DDDDDD")
    C_HEADER_BG = colors.HexColor("#222222")
    C_ZEBRA_A = colors.HexColor("#FFFFFF")
    C_ZEBRA_B = colors.HexColor("#F4F5F7")
    C_FOOTER_BG = colors.HexColor("#EEEEEE")
    C_FOOTER_TXT = colors.HexColor("#333333")
    C_PAPER = colors.HexColor("#FAFAFA")
    OVERLAY_WHITE = colors.Color(1, 1, 1, alpha=0.88)

    doc = SimpleDocTemplate(
        pdf_path,
        pagesize=A4,
        leftMargin=2.0 * cm,
        rightMargin=2.0 * cm,
        topMargin=2.2 * cm,
        bottomMargin=2.0 * cm,
    )

    base_styles = getSampleStyleSheet()

    title_style = ParagraphStyle(
        "PdfTitleStyle",
        parent=base_styles["Title"],
        fontName=font_name,
        fontSize=22,
        leading=28,
        alignment=TA_CENTER,
        textColor=C_HEAD,
        spaceAfter=6,
    )
    subtitle_style = ParagraphStyle(
        "PdfSubtitle",
        parent=base_styles["Normal"],
        fontName=font_name,
        fontSize=11,
        leading=15,
        alignment=TA_CENTER,
        textColor=C_MUTED,
        spaceAfter=18,
    )
    fio_title_style = ParagraphStyle(
        "PdfFioTitle",
        parent=base_styles["Normal"],
        fontName=font_name,
        fontSize=16,
        leading=22,
        alignment=TA_CENTER,
        textColor=C_HEAD,
        spaceAfter=10,
    )
    section_style = ParagraphStyle(
        "PdfSectionTitle",
        parent=base_styles["Heading2"],
        fontName=font_name,
        fontSize=15,
        leading=21,
        alignment=TA_LEFT,
        textColor=C_HEAD,
        spaceBefore=14,
        spaceAfter=10,
    )
    body_style = ParagraphStyle(
        "PdfBodyText",
        parent=base_styles["BodyText"],
        fontName=font_name,
        fontSize=10.5,
        leading=15.5,
        alignment=TA_JUSTIFY,
        textColor=C_TEXT,
        spaceAfter=8,
    )
    body_center_style = ParagraphStyle(
        "PdfBodyCenter",
        parent=body_style,
        alignment=TA_CENTER,
        textColor=C_MUTED,
    )
    highlight_style = ParagraphStyle(
        "PdfHighlight",
        parent=body_style,
        fontName=font_name,
        fontSize=11,
        leading=15,
        textColor=C_HEAD,
        spaceBefore=4,
        spaceAfter=12,
    )
    planet_kicker_style = ParagraphStyle(
        "PdfPlanetKicker",
        parent=base_styles["Normal"],
        fontName=font_name,
        fontSize=11,
        leading=14,
        alignment=TA_LEFT,
        textColor=C_MUTED,
        spaceAfter=4,
    )
    block_heading_style = ParagraphStyle(
        "PdfBlockHeading",
        parent=base_styles["Normal"],
        fontName=font_name,
        fontSize=11,
        leading=14,
        alignment=TA_LEFT,
        textColor=C_HEAD,
        spaceBefore=10,
        spaceAfter=6,
    )
    calc_style = ParagraphStyle(
        "PdfCalcBody",
        parent=base_styles["BodyText"],
        fontName=font_name,
        fontSize=9.5,
        leading=14,
        alignment=TA_LEFT,
        textColor=C_TEXT,
        spaceAfter=12,
    )
    tbl_head = ParagraphStyle(
        "PdfTableHead",
        parent=base_styles["Normal"],
        fontName=font_name,
        fontSize=10,
        leading=13,
        alignment=TA_CENTER,
        textColor=colors.white,
    )
    tbl_cell_l = ParagraphStyle(
        "PdfTableCellL",
        parent=base_styles["Normal"],
        fontName=font_name,
        fontSize=9.5,
        leading=13,
        alignment=TA_LEFT,
        textColor=C_TEXT,
    )
    tbl_cell_c = ParagraphStyle(
        "PdfTableCellC",
        parent=tbl_cell_l,
        alignment=TA_CENTER,
    )

    def _safe_cell(val: object) -> str:
        return html.escape(str(val), quote=False)

    def _draw_full_bleed_bg(canvas, image_path: str, width: float, height: float) -> bool:
        if not os.path.exists(image_path):
            return False
        try:
            img = ImageReader(image_path)
            iw, ih = img.getSize()
            scale = max(width / iw, height / ih)
            draw_w = iw * scale
            draw_h = ih * scale
            x = (width - draw_w) / 2
            y = (height - draw_h) / 2
            canvas.drawImage(img, x, y, width=draw_w, height=draw_h, preserveAspectRatio=True, mask="auto")
            return True
        except Exception as e:
            print("ERROR:", e)
            return False

    story: list = []

    # Титульная страница
    story.append(Spacer(1, 3.2 * cm))
    story.append(Paragraph(_pdf_flowable_text("Статистика Души"), title_style))
    story.append(
        Paragraph(
            _pdf_flowable_text("Персональный нумерологический отчёт"),
            subtitle_style,
        )
    )
    story.append(Spacer(1, 1.4 * cm))
    story.append(Paragraph(f"<b>{html.escape(fio, quote=False)}</b>", fio_title_style))
    story.append(
        Paragraph(_pdf_flowable_text(f"Дата рождения: {birth_date}"), body_center_style)
    )
    story.append(Spacer(1, 1.2 * cm))
    story.append(
        Paragraph(
            _pdf_flowable_text(
                "Документ сформирован на основе расчёта «Древа жизни» по ФИО и дате рождения. "
                "Ниже приведены схема вычислений, сводная матрица сфер и развёрнутый текстовый разбор."
            ),
            body_style,
        )
    )
    story.append(PageBreak())

    # Данные пользователя
    story.append(Paragraph(_pdf_flowable_text("Данные для расчёта"), section_style))
    story.append(Paragraph(_pdf_flowable_text(f"ФИО: {fio}"), body_style))
    story.append(Paragraph(_pdf_flowable_text(f"Дата рождения: {birth_date}"), body_style))
    story.append(PageBreak())

    # Нумерологическая схема расчёта (тот же текст, что в _pdf_build_calc_scheme_paragraphs)
    if calc_snapshot:
        story.append(
            Paragraph(_pdf_flowable_text("Нумерологическая схема расчёта"), section_style)
        )
        story.append(Spacer(1, 0.15 * cm))
        story.append(
            Paragraph(
                _pdf_flowable_text(_pdf_build_calc_scheme_paragraphs(calc_snapshot)),
                calc_style,
            )
        )
        story.append(PageBreak())

    # Персональная матрица
    story.append(Paragraph(_pdf_flowable_text("Персональная матрица"), section_style))
    story.append(Spacer(1, 0.25 * cm))
    summary_rows = [
        [
            Paragraph("<b>СФЕРА</b>", tbl_head),
            Paragraph("<b>ВИБРАЦИЯ</b>", tbl_head),
            Paragraph("<b>ПЛАНЕТА</b>", tbl_head),
        ],
    ]
    for s in sections:
        summary_rows.append(
            [
                Paragraph(_safe_cell(s["title"].upper()), tbl_cell_l),
                Paragraph(_safe_cell(s.get("vibration", "")), tbl_cell_c),
                Paragraph(_safe_cell(_pdf_planet_label_with_emoji(s["planet"])), tbl_cell_c),
            ]
        )
    table_w = A4[0] - doc.leftMargin - doc.rightMargin
    col_a = table_w * 0.46
    col_b = table_w * 0.18
    col_c = table_w * 0.36
    summary_table = Table(summary_rows, colWidths=[col_a, col_b, col_c], repeatRows=1)
    n_data = len(sections)
    zebra_cmds: list[tuple] = []
    if n_data:
        zebra_cmds.append(("ROWBACKGROUNDS", (0, 1), (-1, -1), [C_ZEBRA_A, C_ZEBRA_B]))
    summary_table.setStyle(
        TableStyle(
            [
                ("BACKGROUND", (0, 0), (-1, 0), C_HEADER_BG),
                ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
                ("VALIGN", (0, 0), (-1, -1), "TOP"),
                ("GRID", (0, 0), (-1, -1), 0.4, C_BORDER),
                ("LINEBELOW", (0, 0), (-1, 0), 0.8, C_HEADER_BG),
                ("LEFTPADDING", (0, 0), (-1, -1), 8),
                ("RIGHTPADDING", (0, 0), (-1, -1), 8),
                ("TOPPADDING", (0, 0), (-1, -1), 7),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 7),
            ]
            + zebra_cmds
        )
    )
    story.append(summary_table)
    story.append(PageBreak())

    # Разбор сфер
    for idx, section in enumerate(sections):
        if idx:
            story.append(PageBreak())
        story.append(
            Paragraph(
                _pdf_flowable_text(_pdf_planet_label_with_emoji(section["planet"])),
                planet_kicker_style,
            )
        )
        story.append(Paragraph(_pdf_flowable_text(section["title"]), section_style))
        if section.get("vibration") is not None:
            story.append(
                Paragraph(
                    f"<b>Вибрация:</b> {html.escape(str(section['vibration']), quote=False)}",
                    highlight_style,
                )
            )
        for part_title, part_text in _pdf_split_section_blocks(section["text"]):
            story.append(Paragraph(_pdf_flowable_text(part_title), block_heading_style))
            if part_text:
                text_paragraphs = [p.strip() for p in part_text.split("\n\n") if p.strip()]
                if not text_paragraphs:
                    text_paragraphs = [part_text.strip()]
                for p in text_paragraphs:
                    story.append(Paragraph(_pdf_flowable_text(p), body_style))
                    story.append(Spacer(1, 0.12 * cm))
            story.append(Spacer(1, 0.18 * cm))

    # Итоговый профиль
    story.append(PageBreak())
    story.append(Paragraph(_pdf_flowable_text("Итоговый профиль"), section_style))
    profile_lines: list[str] = []
    for s in sections:
        v = s.get("vibration")
        if v is not None and str(v).strip() != "":
            profile_lines.append(f"• {s['title']} — вибрация {v} ({s.get('planet', '')})")
        else:
            profile_lines.append(f"• {s['title']} ({s.get('planet', '')})")
    brief = (
        "Краткая карта вашего профиля по ключевым сферам и числовым акцентам:\n\n"
        + "\n".join(profile_lines)
    )
    if calc_snapshot:
        cs = calc_snapshot
        brief += (
            f"\n\nТекущий расчётный возраст: {cs['age']} полных лет. "
            f"Номер 7-летнего цикла: {cs['cycle_number']} "
            f"(полоса {cs['cycle_start_age']}–{cs['cycle_end_age']} лет); "
            f"энергия цикла — {cs['cycle_energy']} ({cs['planet_cycle']})."
        )
    story.append(Paragraph(_pdf_flowable_text(brief), body_style))
    story.append(Spacer(1, 0.6 * cm))
    story.append(
        Paragraph(
            _pdf_flowable_text(
                "Если разбор откликается, вы можете поделиться им с тем, кому сейчас важно "
                "лучше понять себя.\n\n"
                "Контакт: @GodStatistics_bot\n"
                "Статистика Души"
            ),
            body_center_style,
        )
    )

    def _draw_page_decor(canvas, doc_obj):
        width, height = A4
        canvas.saveState()
        if not _draw_full_bleed_bg(canvas, AFTER_COVER_BG_PATH, width, height):
            canvas.setFillColor(C_PAPER)
            canvas.rect(0, 0, width, height, stroke=0, fill=1)
        canvas.setFillColor(OVERLAY_WHITE)
        canvas.rect(0, 0, width, height, stroke=0, fill=1)
        canvas.setFillColor(C_FOOTER_BG)
        canvas.rect(0, 0, width, 1.05 * cm, stroke=0, fill=1)
        canvas.setFont(font_name, 8)
        canvas.setFillColor(C_FOOTER_TXT)
        canvas.drawString(1.6 * cm, 0.32 * cm, "Статистика Души")
        canvas.drawRightString(width - 1.6 * cm, 0.32 * cm, f"Стр. {doc_obj.page}")
        canvas.restoreState()

    def _draw_cover_page(canvas, doc_obj):
        width, height = A4
        canvas.saveState()
        if not _draw_full_bleed_bg(canvas, COVER_IMAGE_PATH, width, height):
            canvas.setFillColor(C_PAPER)
            canvas.rect(0, 0, width, height, stroke=0, fill=1)
        canvas.setFillColor(OVERLAY_WHITE)
        canvas.rect(0, 0, width, height, stroke=0, fill=1)
        canvas.setFillColor(C_FOOTER_BG)
        canvas.rect(0, 0, width, 1.05 * cm, stroke=0, fill=1)
        canvas.setFont(font_name, 8)
        canvas.setFillColor(C_FOOTER_TXT)
        canvas.drawString(1.6 * cm, 0.32 * cm, "Статистика Души")
        canvas.drawRightString(width - 1.6 * cm, 0.32 * cm, f"Стр. {doc_obj.page}")
        canvas.restoreState()

    try:
        doc.build(story, onFirstPage=_draw_cover_page, onLaterPages=_draw_page_decor)
    except Exception as e:
        print("ERROR:", e)
        try:
            if pdf_path and os.path.exists(pdf_path):
                os.remove(pdf_path)
        except Exception as err:
            print("ERROR:", err)
        return None
    return pdf_path


async def send_pdf_report(
    update: Update,
    fio: str,
    birth_date: str,
    sections: list[dict],
    calc_snapshot: dict | None = None,
):
    if not update.effective_chat:
        print("❌ Нет chat для отправки PDF")
        return

    status_msg = await update.effective_chat.send_message("⏳ Генерирую PDF...")

    pdf_path = None

    try:
        print("📄 Начинаю генерацию PDF...")
        pdf_path = await asyncio.to_thread(build_pdf_report, fio, birth_date, sections, calc_snapshot)

        if not pdf_path:
            print("❌ build_pdf_report вернул None")
            await status_msg.edit_text("❌ Не удалось создать PDF")
            return

        if not os.path.exists(pdf_path):
            print(f"❌ Файл не найден: {pdf_path}")
            await status_msg.edit_text("❌ PDF не найден после генерации")
            return

        file_size = os.path.getsize(pdf_path)
        print(f"📦 Размер PDF: {file_size}")

        if file_size == 0:
            await status_msg.edit_text("❌ PDF пустой")
            return

        if file_size > 50 * 1024 * 1024:
            await status_msg.edit_text("❌ PDF слишком большой")
            return

        # ASCII-имя файла — кириллица в multipart filename часто ломает клиенты/API
        pdf_filename = f"SoulReport_{birth_date.replace('.', '')}.pdf"

        print("📤 Отправка PDF...")

        with open(pdf_path, "rb") as pdf_file:
            pdf_bytes = pdf_file.read()

        await update.effective_chat.send_document(
            document=InputFile(pdf_bytes, filename=pdf_filename),
            caption="Ваш персональный PDF-разбор готов.",
        )

        await status_msg.edit_text("✅ PDF готов")

        keyboard = InlineKeyboardMarkup([
            [InlineKeyboardButton("🔮 Новый разбор", callback_data="get_stats")],
            [InlineKeyboardButton("💝 Поддержать проект", callback_data="support_project")],
        ])

        await update.effective_chat.send_message(
            "Хочешь разобрать ещё или пойти глубже?",
            reply_markup=keyboard
        )

    except Exception as e:
        print("ERROR:", e)
        await status_msg.edit_text(f"❌ Ошибка:\n{e}")

    finally:
        if pdf_path and os.path.exists(pdf_path):
            try:
                os.remove(pdf_path)
                print("🧹 PDF удалён")
            except Exception as e:
                print("ERROR:", e)

def block_description(num: int, block: dict) -> str:
    # Если это мастер-число, сначала проверяем наличие специального описания
    if num in MASTER_NUMBERS:
        master_key = PLANETS[num]  # Например, "Солнце (мастер)"
        master_data = block.get(master_key)
        if master_data:
            # Используем специальное описание для мастер-числа
            text = (
                f"🔹 Как проявляется:\n{master_data['manifestation']}\n\n"
            )
            # Добавляем "Как задача реализуется в социуме" для социальной задачи
            if 'social_implementation' in master_data:
                text += f"🔹 Как задача реализуется в социуме:\n{master_data['social_implementation']}\n\n"
            text += (
                f"⚠️ Риски:\n{master_data['risks']}\n\n"
                f"✅ Рекомендации:\n{master_data['recommendations']}"
            )
            # Добавляем профессии для социальной задачи
            if 'professions' in master_data:
                text += f"\n\n💼 Профессии и сферы реализации:\n{master_data['professions']}"
            return text
    
    # Если мастер-описания нет или это не мастер-число, используем базовое
    base = PLANETS[num].replace(" (мастер)", "")
    data = block.get(base)
    if not data:
        return ""
    text = (
        f"🔹 Как проявляется:\n{data['manifestation']}\n\n"
        f"⚠️ Риски:\n{data['risks']}\n\n"
        f"✅ Рекомендации:\n{data['recommendations']}"
    )
    if num in MASTER_NUMBERS:
        text += "\n\n✨ Мастер-вибрация усиливает влияние."
    return text

def cycle_description(num: int, cycle: dict) -> str:
    base = PLANETS[num].replace(" (мастер)", "")
    data = cycle.get(base)
    if not data:
        return ""
    text = (
        f"🔹 Как проявляется:\n{data['manifestation']}\n\n"
        f"🎯 Фокус периода:\n{data['focus']}\n\n"
        f"⚠️ Риски:\n{data['risks']}\n\n"
        f"✅ Рекомендации:\n{data['recommendations']}"
    )
    if num in MASTER_NUMBERS:
        text += "\n\n✨ Мастер-цикл — судьбоносный период."
    return text

